//! HLS and DASH manifest validation.
//!
//! Validates manifests generated by [`crate::manifest_builder`] against the
//! rules defined in RFC 8216 (HLS) and MPEG-DASH (DASH).
//!
//! # HLS validation rules
//! - The playlist MUST start with `#EXTM3U`.
//! - Master playlists: each variant MUST be preceded by `#EXT-X-STREAM-INF`
//!   with a `BANDWIDTH=` attribute.
//! - Media playlists: MUST contain `#EXT-X-TARGETDURATION` and
//!   `#EXT-X-MEDIA-SEQUENCE`; each segment URI MUST be preceded by `#EXTINF`.
//! - If `#EXT-X-SKIP` is present, `#EXT-X-VERSION` MUST be >= 9.
//!
//! # DASH validation rules
//! - The root element MUST be `<MPD>`.
//! - At least one `<Period>` element MUST be present.
//! - At least one `<AdaptationSet>` element MUST be present inside a `Period`.
//! - At least one `<Representation>` MUST be present inside each
//!   `AdaptationSet`.
//! - Every `<Representation>` MUST carry a `bandwidth` attribute.

use quick_xml::events::Event;
use quick_xml::Reader;

// ─── Validation error ─────────────────────────────────────────────────────────

/// An error detected during manifest validation.
#[derive(Debug, Clone, PartialEq)]
pub enum ValidationError {
    // ── HLS ──────────────────────────────────────────────────────────────────
    /// The playlist does not start with the required `#EXTM3U` line.
    HlsMissingExtm3u,
    /// A media playlist is missing the `#EXT-X-TARGETDURATION` tag.
    HlsMissingTargetDuration,
    /// A media playlist is missing the `#EXT-X-MEDIA-SEQUENCE` tag.
    HlsMissingMediaSequence,
    /// A variant in a master playlist is missing the `BANDWIDTH=` attribute.
    HlsMissingBandwidth,
    /// `#EXT-X-SKIP` was found but `#EXT-X-VERSION` is less than 9.
    HlsSkipRequiresVersion9,

    // ── DASH ─────────────────────────────────────────────────────────────────
    /// The XML document does not contain an `<MPD>` root element.
    DashMissingMpd,
    /// No `<Period>` element was found inside the MPD.
    DashMissingPeriod,
    /// No `<AdaptationSet>` element was found inside a `Period`.
    DashMissingAdaptationSet,
    /// No `<Representation>` element was found inside an `AdaptationSet`.
    DashMissingRepresentation,
    /// A `<Representation>` element is missing the required `bandwidth`
    /// attribute.
    DashMissingBandwidth,
}

impl std::fmt::Display for ValidationError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::HlsMissingExtm3u => write!(f, "HLS playlist must start with #EXTM3U"),
            Self::HlsMissingTargetDuration => {
                write!(f, "HLS media playlist missing #EXT-X-TARGETDURATION")
            }
            Self::HlsMissingMediaSequence => {
                write!(f, "HLS media playlist missing #EXT-X-MEDIA-SEQUENCE")
            }
            Self::HlsMissingBandwidth => {
                write!(
                    f,
                    "HLS master variant missing BANDWIDTH attribute in #EXT-X-STREAM-INF"
                )
            }
            Self::HlsSkipRequiresVersion9 => {
                write!(f, "#EXT-X-SKIP requires #EXT-X-VERSION:9 or higher")
            }
            Self::DashMissingMpd => write!(f, "DASH MPD missing root <MPD> element"),
            Self::DashMissingPeriod => write!(f, "DASH MPD missing <Period> element"),
            Self::DashMissingAdaptationSet => {
                write!(f, "DASH MPD missing <AdaptationSet> inside <Period>")
            }
            Self::DashMissingRepresentation => {
                write!(
                    f,
                    "DASH MPD missing <Representation> inside <AdaptationSet>"
                )
            }
            Self::DashMissingBandwidth => {
                write!(
                    f,
                    "DASH <Representation> missing required 'bandwidth' attribute"
                )
            }
        }
    }
}

impl std::error::Error for ValidationError {}

// ─── HLS validation ───────────────────────────────────────────────────────────

/// Validate an HLS playlist (master or media) against RFC 8216 rules.
///
/// Returns `Ok(())` if the playlist passes all applicable checks, or the first
/// [`ValidationError`] encountered.
pub fn validate_hls(playlist: &str) -> Result<(), ValidationError> {
    let mut lines = playlist.lines().peekable();

    // Rule 1: must start with #EXTM3U
    match lines.next() {
        Some(line) if line.trim_end() == "#EXTM3U" => {}
        _ => return Err(ValidationError::HlsMissingExtm3u),
    }

    // Scan the rest of the playlist, tracking tags seen.
    let mut is_master = false;
    let mut has_target_duration = false;
    let mut has_media_sequence = false;
    let mut has_skip = false;
    let mut version: u8 = 3; // default HLS version

    let mut stream_inf_seen = false; // last tag was #EXT-X-STREAM-INF

    for line in playlist.lines().skip(1) {
        let trimmed = line.trim_end();

        if trimmed.starts_with("#EXT-X-STREAM-INF:") {
            is_master = true;
            // Verify BANDWIDTH= attribute is present
            if !trimmed.contains("BANDWIDTH=") {
                return Err(ValidationError::HlsMissingBandwidth);
            }
            stream_inf_seen = true;
            continue;
        }

        if trimmed.starts_with("#EXT-X-TARGETDURATION:") {
            has_target_duration = true;
            continue;
        }

        if trimmed.starts_with("#EXT-X-MEDIA-SEQUENCE:") {
            has_media_sequence = true;
            continue;
        }

        if trimmed.starts_with("#EXT-X-VERSION:") {
            if let Some(v_str) = trimmed.strip_prefix("#EXT-X-VERSION:") {
                version = v_str.trim().parse().unwrap_or(3);
            }
            continue;
        }

        if trimmed.starts_with("#EXT-X-SKIP") {
            has_skip = true;
            continue;
        }

        // Non-comment, non-empty lines after #EXT-X-STREAM-INF are variant URIs
        if !trimmed.is_empty() && !trimmed.starts_with('#') {
            stream_inf_seen = false; // URI consumed the stream-inf tag
        }
    }

    // Rule: #EXT-X-SKIP requires version >= 9
    if has_skip && version < 9 {
        return Err(ValidationError::HlsSkipRequiresVersion9);
    }

    // Media playlist rules (only applicable if not a master playlist)
    if !is_master {
        if !has_target_duration {
            return Err(ValidationError::HlsMissingTargetDuration);
        }
        if !has_media_sequence {
            return Err(ValidationError::HlsMissingMediaSequence);
        }
    }

    let _ = stream_inf_seen; // suppress unused warning
    Ok(())
}

// ─── DASH validation ──────────────────────────────────────────────────────────

/// Validate a DASH MPD XML document against structural MPEG-DASH rules.
///
/// Uses a SAX-style event walk via `quick-xml` so the document does not need
/// to be loaded into memory as a tree.
///
/// Returns `Ok(())` on success or the first [`ValidationError`] detected.
pub fn validate_dash(mpd_xml: &str) -> Result<(), ValidationError> {
    let mut reader = Reader::from_str(mpd_xml);
    reader.config_mut().trim_text(true);

    let mut found_mpd = false;
    let mut found_period = false;
    let mut found_adaptation_set = false;
    let mut found_representation = false;

    // depth tracking for nested context
    let mut in_adaptation_set = false;

    loop {
        match reader.read_event() {
            Ok(Event::Start(ref e)) | Ok(Event::Empty(ref e)) => {
                let name = e.name();
                let local = name.local_name();
                let tag = std::str::from_utf8(local.as_ref()).unwrap_or("");

                match tag {
                    "MPD" => {
                        found_mpd = true;
                    }
                    "Period" => {
                        found_period = true;
                    }
                    "AdaptationSet" => {
                        found_adaptation_set = true;
                        in_adaptation_set = true;
                    }
                    "Representation" if in_adaptation_set => {
                        found_representation = true;
                        // Verify bandwidth attribute
                        let has_bw = e.attributes().filter_map(|a| a.ok()).any(|a| {
                            std::str::from_utf8(a.key.local_name().as_ref()).unwrap_or("")
                                == "bandwidth"
                        });
                        if !has_bw {
                            return Err(ValidationError::DashMissingBandwidth);
                        }
                    }
                    _ => {}
                }
            }
            Ok(Event::End(ref e)) => {
                let name = e.name();
                let local = name.local_name();
                let tag = std::str::from_utf8(local.as_ref()).unwrap_or("");
                if tag == "AdaptationSet" {
                    in_adaptation_set = false;
                }
            }
            Ok(Event::Eof) => break,
            // Ignore other events (Decl, Comment, Text, etc.)
            Ok(_) => {}
            Err(_) => {
                // Parse errors are treated as structural failures; if MPD was
                // not found yet, report that.
                break;
            }
        }
    }

    if !found_mpd {
        return Err(ValidationError::DashMissingMpd);
    }
    if !found_period {
        return Err(ValidationError::DashMissingPeriod);
    }
    if !found_adaptation_set {
        return Err(ValidationError::DashMissingAdaptationSet);
    }
    if !found_representation {
        return Err(ValidationError::DashMissingRepresentation);
    }

    Ok(())
}
